// Opaque cursor: base64url-encode the last-seen sort key.
// Include a version so you can evolve the format safely.
interface CursorPayload {
  v: 1;
  createdAt: string; // ISO-8601 of last row
  id: number;        // tiebreaker
}

export function encodeCursor(p: CursorPayload): string {
  const json = JSON.stringify(p);
  return Buffer.from(json, 'utf8').toString('base64url');
}

export function decodeCursor(token: string): CursorPayload {
  const json = Buffer.from(token, 'base64url').toString('utf8');
  const p = JSON.parse(json) as CursorPayload;
  if (p.v !== 1 || typeof p.id !== 'number' || !p.createdAt) {
    throw new Error('invalid_cursor');
  }
  return p;
}

-- Exact count: scans all matching rows every call. Expensive at scale.
SELECT count(*) FROM posts WHERE author_id = 7;

-- Cheap approximate count (Postgres planner estimate for the whole table):
SELECT reltuples::bigint AS approx_rows
FROM pg_class WHERE relname = 'posts';

-- For filtered approximate counts, EXPLAIN gives the planner's row estimate
-- without executing the scan:
EXPLAIN SELECT id FROM posts WHERE author_id = 7;

// Relay-style connection types
type PostConnection = {
  edges: Array<{ node: Post; cursor: string }>;
  pageInfo: {
    hasNextPage: boolean;
    hasPreviousPage: boolean;
    startCursor: string | null;
    endCursor: string | null;
  };
};

